        "# MÔ PHỎNG VÀ ĐỀ XUẤT CHO TƯƠNG LAI\n",
        "\n",
        "try:\n",
        "    # Truyền thẳng biến chứa mô hình mà bạn đã huấn luyện (chỉ cần đổi tên rf_model thành tên biến của bạn)\n",
        "    best_model = rf_model # (Hoặc model, rf, clf... tùy bạn đặt tên ở trên)\n",
        "\n",
        "    # 1. Chạy mô phỏng kịch bản (What-if Scenario)\n",
        "    simulate_future_scenarios(best_model, X_test)\n",
        "\n",
        "    # 2. Chạy hệ thống cảnh báo sớm (Real-time Recommender)\n",
        "    proactive_action_recommender(best_model, X_test, sample_size=5)\n",
        "\n",
        "except NameError as e:\n",
        "    print(f\"Lỗi: {e}\")"
